import { jetstream } from "jibo";

const MINS_TO_MS = 60 * 1000;
const HOURS_TO_MS = 60 * MINS_TO_MS;

export class Utils {

    static minutesToMs(minutes: number): number {
        return minutes * MINS_TO_MS;
    }

    static hoursToMs(hours: number): number {
        return hours * HOURS_TO_MS;
    }

    /**
     * extracts whether a mimResult has a valid intent
     * @static
     * @param mimResults
     * @returns {string} the intent or noMatch/noInput
     */
    static extractIntentFromMIMResults(mimResults): string {
        const mimResult = mimResults.mimResult;
        let intent = ''; // falsey string value
        if (mimResult && mimResult.asrResults) {
            let resultState = jetstream.types.ListenResultState[mimResult.asrResults.state];
            if (resultState === jetstream.types.ListenResultState.match) {
                intent = mimResult.asrResults.intent;
            } else {
                // intent is either noInput or noMatch (or null indicating something broken upstream)
                intent = resultState;
            }
        }
        return intent;
    }
}