import jibo = require('jibo');
import { GreetingsRunVariables } from '../Types';
import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../GreetingsSM';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;


/**
 * Logic for the selfID greeting intent
 */
export class SelfIdState extends sm.State {

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `Self ID`);
        this.onEntry = this._onEntry.bind(this);
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        const skill = this.statemachine.skill;

        data.greeted = true;
        data.verbal = true;
        
        skill.log.debug(`selfID`);
        if (data.user) {
            data.useName = true;
            if (data.selfid !== data.user.uuid) { // selfID conflicts with Jibo's reco
                data.mimId = 'NameIDConflict';
            } else {
                // no conflict, we already knew new this person
                data.mimId = 'BriefGreeting';
            }
        } else {
            skill.log.info('selfID with no robot ID');
            data.mimId = 'BriefGreeting';
        }

        return data;
    }
}