import { GreetingsRunVariables, Intents, EmpathyResponse } from '../Types';
import { GreetingsSM } from '../GreetingsSM';
import { YesNoState } from './primitives/YesNoState';
import { libraries } from '@be/be-framework';
import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;
import { GreetingsSkill } from '../GreetingsSkill';

export class ShouldDoSleepEmpathy extends YesNoState {

    PROBABILITY_OF_UNKNOWN_SLEEP_EMPATHY = 0.80; // Do sleep empathy 80% of the time given the right conditions

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `Should Do Sleep Empathy?`);
        this.onEntry = this._onEntry.bind(this);
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        const skill = this.statemachine.skill;

        // Don't allow empathy questions to trigger off of whats up intents
        if (data.intent === Intents.whatsUp) {
            return this.transitionToNoState(data);
        }

        let uuid;
        if (data.user) {
            uuid = data.user.uuid;
        } else { // Don't do sleep empathy without an ID'd user or if we stochastically chose not to
            return this.transitionToNoState(data);
        }

        let userSleepEmpathy = data.kbRoot.data.sleepEmpathy && data.kbRoot.data.sleepEmpathy[uuid];
        let previousResponse = EmpathyResponse.UNKNOWN; // indicates the user wasn't asked previously
        if (userSleepEmpathy && userSleepEmpathy.sleepQuality && userSleepEmpathy.qualityTimestamp) { // has this node been initialized
            const sleepQuality = userSleepEmpathy.sleepQuality;
            let qualityTimestamp = userSleepEmpathy.qualityTimestamp; // This is a 'let' to allow for expedited testing in the debugger

            const now = skill.dateProvider.getDate().getTime();
            if (cu.TimeUtils.sameDay(now, qualityTimestamp)) { // Don't offer this question more than once a day
                return this.transitionToNoState(data);
            }
            if ((now - qualityTimestamp) < cu.TimeUtils.hoursToMs(skill.EMPATHY_RESET_HOURS)) { // Within acceptable window
                const response = EmpathyResponse[sleepQuality];
                if (response) {
                    previousResponse = response;
                } else {
                    skill.log.error(`Invalid sleep response in kb ${sleepQuality}. Defaulting to ${previousResponse}.`);
                }
            } else {
                // Invalidate the previous answer
                data.kbRoot.data.sleepEmpathy[uuid].sleepQuality = EmpathyResponse.UNKNOWN;
                try {
                    await data.kbRoot.save();
                } catch (error) {
                    skill.log.error("Couldn't invalidate sleep quality: ", error);
                }
            }
        } else { // initialize the node with empty objects.
            try {
                await this.initializeAndSaveSleepEmpathy(data, uuid);
            } catch (error) {
                skill.log.error("Couldn't initialize kbroot fields: ", error);
            }
        }

        // Only ask sleep empathy questions some of the time when we don't know the user's sleep state
        if ((previousResponse === EmpathyResponse.UNKNOWN) && (Math.random() > this.PROBABILITY_OF_UNKNOWN_SLEEP_EMPATHY)) {
            this.transitionToNoState(data);
        }

        return this.transitionToYesState(data);
    }

    /**
     * Initialize the kb node for sleep empathy and save it, handle case where earlier saves failed.
     * Put into function to stub out during test
     * @param {GreetingsRunVariable} data to initialize and save
     * @param {string} uuid of user
     * @return {Promise<any>} result of call to save.
     */
    private initializeAndSaveSleepEmpathy(data: GreetingsRunVariables, uuid:  string): Promise<any> {
        if (data.kbRoot.data.sleepEmpathy) {
            data.kbRoot.data.sleepEmpathy[uuid] = {
                sleepQuality: EmpathyResponse.UNKNOWN,
                qualityTimestamp: this.statemachine.skill.dateProvider.getDate().getTime()
            };
        } else {
            data.kbRoot.data.sleepEmpathy = {
                [uuid]: {
                    sleepQuality: EmpathyResponse.UNKNOWN,
                    qualityTimestamp: this.statemachine.skill.dateProvider.getDate().getTime()
                }
            }
        }
        return data.kbRoot.save().catch((error) => this.statemachine.skill.log.error("Could not initialize and save sleep empathy."));
    }
}