import {BeSkill, utils, libraries} from '@be/be-framework';
import jibo = require('jibo');
import * as path from 'path';
import cu = libraries.jibo_cai_utils;
import { GreetingsRunVariables, Intents, UserInfo, DoMimResults, DateProvider, SkillOptions } from './Types';
import { Utils } from './utils/Utils';
import { LoopUtils } from './utils/LoopUtils';
import { GreetingsSM } from './GreetingsSM';
import * as _ from 'lodash/lodash.min';
import PackageUtils from '../../be-framework/lib/dts/utils/PackageUtils';

const { PromiseUtils, TimeUtils } = libraries.jibo_cai_utils;
const sm = libraries.jibo_state_machine;

export class GreetingsSkill extends BeSkill {

	/**
	 * The dateProvider insulates us from the weirdness of the system being stuck in UTC.
	 * @type {any}
	 */
	dateProvider: DateProvider = null;

	loopUtils = new LoopUtils(this);

	session: cu.SessionManager;

	greetingsModel: jibo.kb.Model;
	greetingsRoot: jibo.kb.Node;

	// Previously we avoided having these run variables as instance variables of the class
	// to protect in the case of multiple simultaneous runs.
	// Now we have the session manager, and a need to have a reference to the blackboard even
	// if the state machine is interrupted. So I'm grafting this on ex post facto, in as
	// low-impact a way as possible.
	blackboard: GreetingsRunVariables = null;

	/**
	 * Whether we allow optional responses or not.
	 */
	readonly ALLOW_OPTIONAL_RESPONSE = true;

	/**
	 * Whether we offer sleep empathy questions
	 */
	readonly ALLOW_SLEEP_EMPATHY = true;
	readonly EMPATHY_RESET_HOURS = 36; // After this number of hours, reset the sleep empathy interaction


	sm = new GreetingsSM(this);
	convTechLog: typeof jibo.log = null;

	/**
	 * Greetings skill constructor
	 * @constructor
	 * @param {any} [data=''] The asset pack if loading from Be
	 */
	constructor(data?: any, private unitTestMode = false) {
		super(data);
		// Creates new session given launch options
		const sessionCreate = (options: SkillOptions = {}) => {
			return {
				promise: this._open(options),
				stop: () => this.sm.stop()
			};
		};

		this.session = new cu.SessionManager(
			sessionCreate,
			() => this.exit(),
			this.log);
	}

	/**
	 * Called after the skill has been created and initialized.
	 * @param {Function} done
	 */
	postInit(done) {
		// Here we create a localized date provider using jiboHome and give to interaction memory
		// This takes into account Jibo's home timezone offset
		let offset = 0;
		try {
			offset = utils.Location.jiboHome.timezone.offsetUTC;
		} catch (e) {
			this.log.warn(`error getting timezone offset (using 0 instead): ${e}`);
		}
		this.dateProvider = new DateProvider(offset);
		this.convTechLog = this.log.createChild('ConvTechSpeakerID');
		// initialize the knoweldge base for greetings if we're not doing unit tests
		if (!this.unitTestMode) {
			this.greetingsModel = jibo.kb.createModel('/skills/greetings');
			this.greetingsModel.loadRoot((err, root) => {
				if (root) {
					this.greetingsRoot = root;
				}
			});
		}
		done();
	}

	/**
	 * Called just before skill starts
	 * @param done
	 */
	preload(done: (err?: any)=>void): void {
		// force the eye view to be visible, in case the preceding skill hid it.
		jibo.face.views.forceEyeView(); // this is async, but I don't think we want to wait for it.
		done();
	}

	/**
	 * Start the skill
	 * @method open
	 */
	open(options?: SkillOptions, refresh?: boolean): void { // Options include ASR, intent, everything else.
		if (refresh) {
			this.session.replaceSession(options);
		} else {
			this.session.open(options);
		}
	}

	/**
	 * Stop and unload the skill
	 * @method close
	 */
	close(done: (err?: any) => void): void {
		this.session.close()
			.then(() => done())
			.catch(e => done(e));
	}

	async _open(options: SkillOptions = {}): Promise<void> { // TODO: Siggi makes this return a string in SurpriseDate
		try {
			await this.sm.start(options);
		} catch (e) {
			this.log.error(`Error running greetings state machine: `, e);
		}

		// let's log the interaction here, with whatever info we need.
		// For now: user, was greeting verbal, was greeting proactive
		if (this.blackboard && this.blackboard.greeted) {
			let eventDesc: any = {
				skillName: this.assetPack,
				verbal: this.blackboard.verbal,
				proactive: this.blackboard.proactive
			};
			if (this.blackboard.user) {
				eventDesc.personIDs = [this.blackboard.user.uuid];
			}
			this.log.debug('recording greeting in interaction memory');
			jibo.im.noteEvent(eventDesc);
		} else {
			this.log.warn(`conditions not met for recording greeting in interaction memory`);
		}
		// apply motivational effect
		if (this.blackboard && this.blackboard.greeted && this.blackboard.verbal) {
			let socialDriveValueBefore = jibo.action.getMotivationalDriveValue(jibo.action.types.DriveName.SOCIAL);
			jibo.action.applyMotivationalEffect(jibo.action.types.DriveName.SOCIAL, -0.4);
			let socialDriveValueAfter = jibo.action.getMotivationalDriveValue(jibo.action.types.DriveName.SOCIAL);
			this.log.info(`Greetings applied motivational effect on SOCIAL: ${socialDriveValueBefore} -> ${socialDriveValueAfter}`);
		} else {
			this.log.warn(`conditions not met for applying motivational effect on SOCIAL`);
		}

		// do analytics logging
		if (this.blackboard) {
			this.analyticsEvents(this.blackboard);
		}

		// a few debug logs, just in case
		// Diagnostic information at the debug level.
		this.log.debug(`SM trace: ${this.sm.traceToString()}`);
		// gotta remove the pronounceable name before logging blackboard
		let logBlackboard: GreetingsRunVariables = _.cloneDeep(this.blackboard);
		if (logBlackboard && logBlackboard.user && logBlackboard.user.spokenName) {
			logBlackboard.user.spokenName = '[REDACTED]';
		}
		if (logBlackboard && logBlackboard.lastMiMResults && logBlackboard.lastMiMResults.mimResult &&
				logBlackboard.lastMiMResults.mimResult.asrResults) {
			logBlackboard.lastMiMResults.mimResult.asrResults.text = '[REDACTED]';
		}
		this.log.debug('blackboard: ', logBlackboard);

	}

	/**
	 * Initialize a run-state "blackboard", holding all the state for a run through Greetings.
	 *
	 * @param {SkillOptions} options - containing the ListenResults and/or other launch options
	 * @type {{}}
	 */
	async initializeBlackboard(options: SkillOptions): Promise<GreetingsRunVariables> {
		let activeHolidays: Set<string> = await BeSkill.plugins.holiday.getActiveHolidaySet();

		// make sure the greetingsRoot has been initialized
		if (!this.greetingsRoot.data.sleepEmpathy || !this.greetingsRoot.data.dayEmpathy) {
			await this.initializeEmpathyFields();
		}

		let data: GreetingsRunVariables = {
			intent: this.extractIntent(options),
			greeted: false, // did we actually greet the user?
			verbal: false, // was the greeting verbal?
			proactive: false, // was this a proactive greeting?
			user: undefined,
			useName: true,
			PODclaim: undefined, // TODO: in further refactoring, it might be cool to pass this kind of single-use-case mim info into doMim directly
			holiday: undefined,
			holidayClaim: this.extractHolidayClaim(options),
			mimId: undefined,
			selfid: this.extractSelfID(options),
			isBday: false,
			lastMiMResults: undefined,
			userResponse: false,
			activeHolidays: activeHolidays,
			ORQuestion: false,
			kbRoot: this.greetingsRoot
		};

		// Get user info
		let uuid = this.pollIdentityForUser(data); // could be null!
		// if uuid, get spoken name from KB
		if (uuid) {
			let spoken = await this.loopUtils.spokenNameFromUUID(uuid);
			if (spoken) { // no spoken name, no user.
				data.user = { uuid: uuid, spokenName: spoken };
			}
		}

		return data;
	}

	/**
	 * Returns whether or not we should use name
	 * @param {GreetingsRunVariables} data
	 * @returns {Promise<boolean>}
	 */
	async shouldUseName(data: GreetingsRunVariables): Promise<boolean> {
		if (!data.user) {
			return false;
		}
		let eventDesc = { personIDs: [data.user.uuid] };
		let res = await jibo.im.getTimeSinceLast(eventDesc);
		// more than 96 hours since LM last seen
		return ((res === null) || (res > Utils.hoursToMs(96)) || (Math.random() > 0.5));
	}

	/**
	 * Extracts the intent from the options data
	 * @param {SkillOptions} options
	 * @returns {string}
	 */
	extractIntent(options: SkillOptions): string {
		if (options && options.nlu) {
			if (options.nlu.intent === Intents.proactiveGreetingCloud) { // Intents.proactiveGreetingCloud === ''
				// The cloud will proactively launch with an empty intent (Intents.proactiveGreetingCloud) to indicate a proactive launch, replace the intent with our local proactive intent. 
				options.nlu.intent = Intents.proactiveGreeting;
			}
			return options.nlu.intent;
		}

		this.log.warn(`No intent found. Doing a heyJibo.`);
		return Intents.heyJibo;
	}

	/**
	 * Extracts the selfid field from the nlu data, if it exists.
	 * @param {SkillOptions} options
	 * @returns {any}
	 */
	extractSelfID(options: SkillOptions): string {
		if (options && options.nlu && options.nlu.entities.selfid) {
			return options.nlu.entities.selfid;
		}
	}

	/**
	 * Extracts the holidayClaim field from the nlu data, if it exists
	 * @param {SkillOptions} options
	 * @returns {any}
	 */
	extractHolidayClaim(options: SkillOptions): string {
		if (options && options.nlu && options.nlu.entities.holiday) {
			return options.nlu.entities.holiday;
		}
	}

	/**
	 * Polls the identity module for the UUID of the user we're currently interacting with
	 * @returns {string|null} UUID of the user, if available, or null.
	 * @private
	 */
	pollIdentityForUser(data: GreetingsRunVariables): string|null {
		// first check active speaker
		if (data.intent !== Intents.proactiveGreeting){
			const person = jibo.lps.identity.getActiveSpeaker();
			if (person) {
				// there's an active speaker. even if they're not IDed, that's the identity we should use.
				// log speakerInfo data for ConvTech confidence tuning
				const speakerInfo = person.idInfo;
				if (speakerInfo) {
					this.convTechLog.info(`Speaker ID: ${speakerInfo.id} | accepted: ${speakerInfo.accepted} | is high confidence: ${speakerInfo.highConfidence} | score: ${speakerInfo.score}`);
					return speakerInfo.id; // could be null.
				}
			}
		} else {
			// if no active speaker, check getPresentPersons; iterate through list for one with id
			const persons = jibo.lps.identity.getPresentPersons();
			const idPerson = persons.find(person => (person.id && person.id !== "UNKNOWN" && person.id !== "NOT_TRAINED"));
			if (idPerson) {
				this.log.info(`lps.identity.getPresentPersons found id: id: ${idPerson.id}, type: ${idPerson.type}, confidence: ${idPerson.confidence}`);
				return idPerson.id;
			}
		}
		// no identified person is present, or no one is present at all (which seems unlikely, but needs to be handled)
		return null;
	}

	/**
	 * Initialize the kb entry
	 */
	async initializeEmpathyFields() {
		this.greetingsRoot.data.sleepEmpathy = {};
		this.greetingsRoot.data.dayEmpathy = {};
		this.greetingsRoot.save().catch((error) => this.log.error('Could not initialize kb.'));
	}

	/************** OUTPUT UTILITIES *****************/

	/**
	 * Returns the current part of day using dateProvider
	 * @returns {PartOfDay}
	 * @private
	 */
	getPartOfDay() {
		return TimeUtils.getPartOfDay(this.dateProvider.getDate()).basic;
	}


	// analytics
	analyticsEvents(blackboard:GreetingsRunVariables):void {
		if (blackboard.greeted) {
			// one event that gives greeting type
			this.log.debug('analytic logging: Greeting Type', {proactive_greeting: blackboard.proactive});
			this.track('Greeting Type', {proactive_greeting: blackboard.proactive});
			// one event with details of either proactive or reactive greeting
			if (blackboard.proactive) {
				this.log.debug('analytic logging: Proactive Greeting', {
					verbal_proactive_greeting: blackboard.verbal,
					loop_member_known: !!blackboard.user,
					user_response: blackboard.userResponse
				});
				this.track('Proactive Greeting', {
					verbal_proactive_greeting: blackboard.verbal,
					loop_member_known: !!blackboard.user,
					user_response: blackboard.userResponse
				});
			} else {
				this.log.debug('analytic logging: Reactive Greeting', {
					verbal_reactive_greeting: blackboard.verbal,
					loop_member_known: !!blackboard.user,
					user_response: blackboard.userResponse
				});
				this.track('Reactive Greeting', {
					verbal_reactive_greeting: blackboard.verbal,
					loop_member_known: !!blackboard.user,
					user_response: blackboard.userResponse
				});
			}
		} else {
			this.log.warn(`Greetings tried to log analytic events, but blackboard.greeted was false, which was unexpected.`);
		}
	}

	/**
	 * Override the skills track function and only call it when we're running on the robot
	 * @param event the name of the event to track
	 * @param data the data to track with the event
	 */
	track(event: string, data?: any) {
		if (jibo.runMode === jibo.RunMode.ON_ROBOT) {
			super.track(event, data);
		}
	}
}
