import jibo = require('jibo');
import { GreetingsRunVariables, Intents, EmpathyResponse, SleepEmpathy } from '../Types';
import { GreetingsSM } from '../GreetingsSM';
import { YesNoState } from './primitives/YesNoState';
import { libraries } from '@be/be-framework';
import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;
import { SleepEmpathyQuestionState } from './SleepEmpathyQuestionState';

export class ShouldDoBedtimeReminderState extends YesNoState {

    static REMINDER_WINDOW_MS = cu.TimeUtils.hoursToMs(64); // Sleep empathy information is valid for this long

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `Should Do Bedtime Reminder?`);
        this.onEntry = this._onEntry.bind(this);
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        const skill = this.statemachine.skill;

        // Don't allow empathy questions to trigger off of whats up intents
        if (data.intent === Intents.whatsUp) {
            return this.transitionToNoState(data);
        }

        // Have we ID'd the user?
        let uuid: string;
        if (data.user) {
            uuid = data.user.uuid;
        } else { // Don't do sleep empathy without an ID'd user or if we stochastically chose not to
            return this.transitionToNoState(data);
        }
        
        // Is it the right time of day (8 - 10pm)?
        const today = skill.dateProvider.getDate();
        const hours = today.getHours();
        if (hours < 20 || 21 < hours) {
            return this.transitionToNoState(data);
        }
        
        // Did the user sleep poorly?
        const sleepEmpathy = this.extractSleepEmpathyForUser(data.kbRoot, uuid);
        const now = today.getTime();
        if (sleepEmpathy.sleepQuality !== EmpathyResponse.BAD || // the user didnt' sleep badly
        ((now - sleepEmpathy.qualityTimestamp > ShouldDoBedtimeReminderState.REMINDER_WINDOW_MS))) { // we have stale info
            return this.transitionToNoState(data);
        }
        
        // Did the user get a bedtime reminder today?
        if (cu.TimeUtils.sameDay(sleepEmpathy.reminderTimestamp, now)) {
            return this.transitionToNoState(data);
        }

        return this.transitionToYesState(data);
    }

    /**
     * Extract sleep empathy info from the kb and sanitize for easy use.
     * @param {jibo.kb.Node} kbRoot root of kb
     * @param {string} uuid user id
     * @return {SleepEmpathy} object with sleep empathy info
     */
    private extractSleepEmpathyForUser(kbRoot: jibo.kb.Node, uuid: string): SleepEmpathy {
        const sleepEmpathy: SleepEmpathy = {
            sleepQuality: EmpathyResponse.UNKNOWN,
            qualityTimestamp: 0,
            reminderTimestamp: 0
        };

        const kbData = kbRoot.data;
        // put in default values if kb knowledge is invalid
        try { // is this data good?
            sleepEmpathy.reminderTimestamp = kbData.sleepEmpathy[uuid].reminderTimestamp; 
            sleepEmpathy.qualityTimestamp = kbData.sleepEmpathy[uuid].qualityTimestamp;
            sleepEmpathy.sleepQuality = kbData.sleepEmpathy[uuid].sleepQuality;
        } catch {
            sleepEmpathy.reminderTimestamp = 0; // the dawn of time
            sleepEmpathy.qualityTimestamp = 0; // the dawn of time
            sleepEmpathy.sleepQuality = EmpathyResponse.UNKNOWN;
        }
        return sleepEmpathy;
    }
}