import jibo = require('jibo');
import { GreetingsRunVariables, ProactiveGreetingType } from '../Types';
import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../GreetingsSM';
import { Utils } from '../utils/Utils';
import { YesNoState } from './primitives/YesNoState';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

import DriveName = jibo.action.types.DriveName;

/**
 * Logic for the proactive proactiveGreeting intent
 */
export class ProactiveGreetingState extends YesNoState {

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `Proactive Greeting`);
        this.onEntry = this._onEntry.bind(this);
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        const skill = this.statemachine.skill;

        data.proactive = true;
        let eventDesc: any = {
            skillName: skill.assetPack,
            verbal: true
        };
        if (data.user) {
            skill.log.info(`proactiveGreeting with an identity!: ${data.user.uuid}`);
            data.useName = true; // it should have been set to true already, but just in case...
            eventDesc.personIDs = [data.user.uuid];
        } else {
            skill.log.info(`proactiveGreeting without an identity.`);
            data.useName = false;
        }

        // no longer need to check social drive or interaction memory because its done before the skill launched
        // choose a "flavor"
        const drives = [DriveName.PLAYFUL]; // originally we were going to have others, but then playful was the only one that seemed relevant.
        // get drive value for each relevant motivational drive
        let weighted = drives.map(d => {
            return { data: d, weight: jibo.action.getMotivationalDriveValue(d) };
        });
        // (use None with value 0.5?) give some positive value to none so small drive values don't dominate
        weighted.push({ data: null, weight: 0.5 });
        // do a weighted sample by drive value
        skill.log.debug(`doing weighted sample from: `, weighted);
        let driveChoice = cu.RandomUtils.weightedRandomSample(weighted);
        // do a proactiveVerbalGreeting
        if (driveChoice) {
            let motivationalFlavor = driveChoice as jibo.action.types.DriveName;
            let flavorDriveValueBefore = jibo.action.getMotivationalDriveValue(motivationalFlavor);
            jibo.action.applyMotivationalEffect(motivationalFlavor, -1.0);
            let flavorDriveValueAfter = jibo.action.getMotivationalDriveValue(motivationalFlavor);
            skill.log.info(`Greetings applied motivational effect on ${motivationalFlavor}: ${flavorDriveValueBefore} -> ${flavorDriveValueAfter}`);
        }

        if (this.isPlayful(driveChoice)) {
            data.mimId = 'ProactiveVerbalGreetingPlayful';
            data.proactiveGreetingType = ProactiveGreetingType.PLAYFUL;
        } else {
            data.mimId = 'ProactiveVerbalGreetingDefault';
            data.proactiveGreetingType = ProactiveGreetingType.REGULAR; 
        }
        data.greeted = true;
        data.verbal = true;
        return this.transitionToYesState(data);
    }

    /**
     * Check whether the playful drive was chosen
     * wrapped in order to stub out for testing
     * @param {DriveName} name of drive to check
     */
    private isPlayful(driveChoice: any): boolean {
        return (driveChoice && driveChoice === jibo.action.types.DriveName.PLAYFUL);
    }

    /**
     * Provides a random number in a specific point in the flow. Extracted to be overridden in tests
     * @returns {number} 
     */
    private randomUseName(): number {
        return Math.random();
    }

    /**
     * Provides a random number in a specific point in the flow. Extracted to be overridden in tests
     * @returns {number} 
     */
    private randomFriendlyGesture(): number {
        return Math.random();
    }
}
