import jibo = require('jibo');
import { GreetingsRunVariables } from '../Types';
import { Utils } from '../utils/Utils';
import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../GreetingsSM';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;


export class HeyJiboIntentState extends sm.State {

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `Hey Jibo Intent`);
        const skill = this.statemachine.skill;
        this.onEntry = (trans, data: GreetingsRunVariables) => {
            data.greeted = true;
            data.verbal = false;
            // friendly gesture
            data.mimId = 'FriendlyGesture';
            return data;
        };
    }
}
