import jibo = require('jibo');
import { GreetingsRunVariables, SpecialDayType } from '../Types';
import { libraries } from '@be/be-framework';
import { GreetingsSkill } from '../GreetingsSkill';
import { VerbalGreetedMIMState } from './VerbalGreetedMiMState';
import { MIMIDSelector } from './primitives/DoMiMState';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

/**
 * A VerbalGreetedMIMState that also notes through InteractionMemory that a special day greeting occurred
 */
export class HolidayMIMState extends VerbalGreetedMIMState {

    constructor(statemachine: sm.StateMachine, skill: GreetingsSkill, name: string, specialDayType: SpecialDayType, mimIdSelector?: MIMIDSelector) {
        super(statemachine, skill, name, mimIdSelector);

        const superOnEntry = this.onEntry.bind(this);
        this.onEntry = (trans, data: GreetingsRunVariables) => {
            const skill = this.skill;

            // log that we did a special day greeting
            let eventDesc: any = {
                skillName: skill.assetPack,
            };
            eventDesc[specialDayType] = true;
            if (data.user) {
                eventDesc.personIDs = [data.user.uuid];
            }

            if (data.holiday) {
                // Save the specific holiday this greeting was about. 
                eventDesc.holiday = data.holiday;
            }
            
            jibo.im.noteEvent(eventDesc); // this is async, but we don't really care.

            // And now we perform the MiM
            return superOnEntry(trans, data);
        }
    }
}
