import jibo = require('jibo');
import { GreetingsRunVariables } from '../Types';
import { libraries } from '@be/be-framework';
import { GreetingsSkill } from '../GreetingsSkill';
import { DoMIMState, MIMIDSelector } from './primitives/DoMiMState';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;


/**
 * A DoMIM State that specifies in the data flow object that a verbal greeting occurred
 */
export class VerbalGreetedMIMState extends DoMIMState {

    constructor(statemachine: sm.StateMachine, skill: GreetingsSkill, name: string, selector?: MIMIDSelector) {
        super(statemachine, skill, name, selector);

        const superOnEntry = this.onEntry.bind(this);
        this.onEntry = (trans, data: GreetingsRunVariables) => {
            data.verbal = true;
            data.greeted = true;
            // And now we perform the MiM
            return superOnEntry(trans, data);
        };
    }
}
