import jibo = require('jibo');
import { GreetingsRunVariables } from '../Types';
import { Utils } from '../utils/Utils';
import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../GreetingsSM';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;


export class SelectWhatsUpState extends sm.State {

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `What's Up`);
        this.onEntry = this._onEntry.bind(this);
    }

    async _onEntry(trans, data: GreetingsRunVariables): Promise<any> {
        const skill = this.statemachine.skill;
        // if user IDed and not seen in 96 hours
        let timeSinceLastSeen = 0;
        if (data.user) {
            const eventDesc = { personIDs: [data.user.uuid] };
            try {
                timeSinceLastSeen = await jibo.im.getTimeSinceLast(eventDesc);
            } catch (error) {
                skill.log.warn("Couldn't get time since last: ", error);
            }
        }
        if (timeSinceLastSeen > Utils.hoursToMs(96)) {
            data.mimId = 'LongTimeWhatsUpResp';
        } else {
            data.mimId = 'WhatsUpResp';
        }
        // TODO: refactor so greeted and verbal are set at mim delivery time
        data.greeted = true;
        data.verbal = true;
        return data;
    }
}
