import jibo = require('jibo');
import { GreetingsRunVariables, ProactiveGreetingType, OptionalResponseIntent } from '../Types';
import { libraries } from '@be/be-framework';
import { GreetingsSkill } from '../GreetingsSkill';
import { DoMIMState } from './primitives/DoMiMState';
import { Utils } from '../utils/Utils';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

const PUZZLED = 'PuzzledGesture';
const FRUSTRATED_RESPONSE = 'FrustratedResponse';
const HAPPY_GESTURE = 'HappyGesture';
const FRIENDLY_RESPONSE_PLAYFUL = 'FriendlyResponsePlayful';
const FRIENDLY_RESPONSE_MORNING = 'FriendlyResponseMorning';
const FRIENDLY_RESPONSE_GENERAL = 'FriendlyResponseGeneral';
const GENERAL_COUNTER_QUESTION = 'ProactiveGeneralCounter';
const PLAYFUL_COUNTER_QUESTION = 'ProactivePlayfulCounter';
const WHATS_UP_RESPONSE = 'WhatsUpResp';


// setup up the maps between intents and mims
const morningStatementIntentMap: Map<OptionalResponseIntent, string> = new Map([
    [OptionalResponseIntent.returned, FRIENDLY_RESPONSE_MORNING],
    [OptionalResponseIntent.wildcard, PUZZLED],
    [OptionalResponseIntent.frustrated, FRUSTRATED_RESPONSE],
    [OptionalResponseIntent.playfulResponse, HAPPY_GESTURE],
    [OptionalResponseIntent.counterQuestion, GENERAL_COUNTER_QUESTION],
    [OptionalResponseIntent.whatsUp, WHATS_UP_RESPONSE],
]);
const playfulStatementIntentMap: Map<OptionalResponseIntent, string> = new Map([
    [OptionalResponseIntent.returned, FRIENDLY_RESPONSE_PLAYFUL],
    [OptionalResponseIntent.wildcard, PUZZLED],
    [OptionalResponseIntent.frustrated, FRUSTRATED_RESPONSE],
    [OptionalResponseIntent.playfulResponse, HAPPY_GESTURE],
    [OptionalResponseIntent.counterQuestion, PLAYFUL_COUNTER_QUESTION],
    [OptionalResponseIntent.whatsUp, WHATS_UP_RESPONSE],
]);
const generalStatementIntentMap: Map<OptionalResponseIntent, string> = new Map([
    [OptionalResponseIntent.returned, FRIENDLY_RESPONSE_GENERAL],
    [OptionalResponseIntent.wildcard, PUZZLED],
    [OptionalResponseIntent.frustrated, FRUSTRATED_RESPONSE],
    [OptionalResponseIntent.counterQuestion, GENERAL_COUNTER_QUESTION],
    [OptionalResponseIntent.whatsUp, WHATS_UP_RESPONSE],
]);
const morningQuestionIntentMap: Map<OptionalResponseIntent, string> = new Map([
    [OptionalResponseIntent.yes, 'ProactiveMorningYes'],
    [OptionalResponseIntent.no, 'ProactiveMorningNo'],
    [OptionalResponseIntent.counterQuestion, 'ProactiveMorningCounter'],
    [OptionalResponseIntent.noMatch, PUZZLED],
    [OptionalResponseIntent.frustrated, FRUSTRATED_RESPONSE],
    [OptionalResponseIntent.returned, FRIENDLY_RESPONSE_MORNING],
    [OptionalResponseIntent.whatsUp, WHATS_UP_RESPONSE],
]);
const playfulQuestionIntentMap: Map<OptionalResponseIntent, string> = new Map([
    [OptionalResponseIntent.good, 'ProactivePlayfulGood'],
    [OptionalResponseIntent.bad, 'ProactivePlayfulBad'],
    [OptionalResponseIntent.counterQuestion, PLAYFUL_COUNTER_QUESTION],
    [OptionalResponseIntent.noMatch, PUZZLED],
    [OptionalResponseIntent.frustrated, FRUSTRATED_RESPONSE],
    [OptionalResponseIntent.soSo, 'ProactivePlayfulSoSo'],
    [OptionalResponseIntent.returned, FRIENDLY_RESPONSE_PLAYFUL],
    [OptionalResponseIntent.whatsUp, WHATS_UP_RESPONSE],
]);
const generalQuestionIntentMap: Map<OptionalResponseIntent, string> = new Map([
    [OptionalResponseIntent.good, 'ProactiveGeneralGood'],
    [OptionalResponseIntent.bad, 'ProactiveGeneralBad'],
    [OptionalResponseIntent.counterQuestion, GENERAL_COUNTER_QUESTION],
    [OptionalResponseIntent.noMatch, PUZZLED],
    [OptionalResponseIntent.frustrated, FRUSTRATED_RESPONSE],
    [OptionalResponseIntent.soSo, 'ProactiveGeneralSoSo'],
    [OptionalResponseIntent.returned, FRIENDLY_RESPONSE_GENERAL],
    [OptionalResponseIntent.whatsUp, WHATS_UP_RESPONSE],
]);

/**
 * A DoMIMState that provides a MiM response dependant on the type of proactive greeting we've done and the intent of the user.
 */
export class ProactiveOptionalResponseState extends DoMIMState {

    constructor(statemachine: sm.StateMachine, skill: GreetingsSkill, name: string) {
        super(statemachine, skill, name, (sm, data) => {
            let intentString = Utils.extractIntentFromMIMResults(data.lastMiMResults);
            let intent: OptionalResponseIntent = OptionalResponseIntent[intentString];

            if (!intent) {
                // this should never happen
                skill.log.error(`Unexpected null intent string for optional response: ${intentString}. Replacing with noInput.`);
                intent = OptionalResponseIntent.noInput;
            } else {
                skill.log.info(`User responded with intent: ${intent}.`);
            }

            // Are we responding to a question or a statement?
            const question = data.ORQuestion;
            const proactiveType = data.proactiveGreetingType;
            let mimIdToUse: string = null;
            switch (proactiveType) {
                case ProactiveGreetingType.MORNING:
                    mimIdToUse = (question) ? morningQuestionIntentMap.get(intent) : morningStatementIntentMap.get(intent);
                    break;
                case ProactiveGreetingType.PLAYFUL:
                    mimIdToUse = (question) ? playfulQuestionIntentMap.get(intent) : playfulStatementIntentMap.get(intent);
                    break
                case ProactiveGreetingType.REGULAR:
                    mimIdToUse = (question) ? generalQuestionIntentMap.get(intent) : generalStatementIntentMap.get(intent);
                    break;
                default:
                    skill.log.error(`Unrecognized proactive greeting type ${proactiveType}`);
                    break;
            }

            skill.log.info(`${(mimIdToUse) ? mimIdToUse : 'No MiM'} chosen for ${(question) ? 'question' : 'statement'} with intent:${intent} and proactiveType:${proactiveType}.`);
            data.userResponse = !!mimIdToUse;
            this.trackProactiveOptionalResponseResult(data, intent);
            return mimIdToUse;
        });
    }

    /**
     * Track results of proactive greeting in a domo event.
     * @param {GreetingsRunVariables} data from this greetings run
     * @param {OptionalResponseIntent} intent of user's response
     */
    private trackProactiveOptionalResponseResult(data: GreetingsRunVariables, intent: OptionalResponseIntent) {
        const results = {
            proactive_sentence_type: (data.ORQuestion ? 'QUESTION' : 'STATEMENT'), // question or statement
            proactive_greeting_type: data.proactiveGreetingType, // morning, friendly, or normal
            person_in_loop: ((data.user && data.user.spokenName && data.useName) ? 'true' : 'false'), // whether we knew who the user was (reused property from other events)
            user_response: intent // how the user responded (resued property from other events)
        };

        this.skill.track('Proactive Results', results);
    }

    /**
     * Get all the mims used in this state for unit tests
     * @return a list of mims used in this state
     */
    public getMIMs() {
        return [PUZZLED,FRUSTRATED_RESPONSE,HAPPY_GESTURE,FRIENDLY_RESPONSE_PLAYFUL,FRIENDLY_RESPONSE_MORNING,FRIENDLY_RESPONSE_GENERAL,GENERAL_COUNTER_QUESTION,PLAYFUL_COUNTER_QUESTION]
    }

}
