import jibo = require('jibo');
import { GreetingsRunVariables, SimpleResponseIntent, EmpathyResponse } from '../Types';
import { libraries } from '@be/be-framework';
import { GreetingsSkill } from '../GreetingsSkill';
import { DoMIMState } from './primitives/DoMiMState';
import { Utils } from '../utils/Utils';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

const SQBadAgain = 'SQBadBad';
const SQBadNowGood = 'SQBadGood';
const SQGoodAgain = 'SQGoodGood';
const SQGoodNowBad = 'SQGoodBad';
const SQError = 'SQError';
const SQFirstGood = 'SQUnknownGood';
const SQFirstBad = 'SQUnknownBad';

// setup up the maps between intents and mims
// response to 'did you sleep better?'
const badSleepIntentMap: Map<SimpleResponseIntent, string> = new Map([
    [SimpleResponseIntent.yes, SQBadNowGood],
    [SimpleResponseIntent.no, SQBadAgain],
    [SimpleResponseIntent.noInput, SQError],
    [SimpleResponseIntent.noMatch, SQError]
]);

// response to 'did you sleep well again?'
const goodSleepIntentMap: Map<SimpleResponseIntent, string> = new Map([
    [SimpleResponseIntent.yes, SQGoodAgain],
    [SimpleResponseIntent.no, SQGoodNowBad],
    [SimpleResponseIntent.noInput, SQError],
    [SimpleResponseIntent.noMatch, SQError]
]);

// response to 'did you get a good nights sleep?'
const unknownSleepIntentMap: Map<SimpleResponseIntent, string> = new Map([
    [SimpleResponseIntent.yes, SQFirstGood],
    [SimpleResponseIntent.no, SQFirstBad],
    [SimpleResponseIntent.noInput, SQError],
    [SimpleResponseIntent.noMatch, SQError]
]);

/**
 * A DoMIMState that provides a MiM response dependant on the type of sleep empathy response we get.
 */
export class SleepEmpathyResponseState extends DoMIMState {

    constructor(statemachine: sm.StateMachine, skill: GreetingsSkill) {
        super(statemachine, skill, 'Sleep Empathy Response', (sm, data) => {
            let intentString = Utils.extractIntentFromMIMResults(data.lastMiMResults);
            let intent: SimpleResponseIntent = SimpleResponseIntent[intentString];

            if (!intent) {
                // this should never happen
                skill.log.error(`Unexpected null intent for sleep empathy response: ${intentString}. Replacing with noInput.`);
                intent = SimpleResponseIntent.noInput;
            } else {
                skill.log.info(`User responded with intent: ${intent}.`);
            }

            // All sleep empathy questions essentially ask "Did you sleep well?"
            let newEmpathyResponse: EmpathyResponse;
            switch (intent) {
                case SimpleResponseIntent.yes:
                    newEmpathyResponse = EmpathyResponse.GOOD;
                    break;
                case SimpleResponseIntent.no:
                    newEmpathyResponse = EmpathyResponse.BAD;
                    break;
                default:
                    newEmpathyResponse = EmpathyResponse.UNKNOWN;
                    break;
            }

            const uuid = data.user.uuid;
            const now = skill.dateProvider.getDate().getTime();
            const userSleepEmpathy = data.kbRoot.data.sleepEmpathy && data.kbRoot.data.sleepEmpathy[uuid];
            let previousResponse = EmpathyResponse.UNKNOWN;
            if (!userSleepEmpathy) {
                this.skill.log.warn("Initiaizing knowledge base fields in SleepEmpathyResponseState, this should've happened earlier");
            } else {
                previousResponse = userSleepEmpathy.sleepQuality;
            }

            let mimIdToUse: string = SQError;
            switch (previousResponse) {
                case EmpathyResponse.BAD:
                    mimIdToUse = badSleepIntentMap.get(intent);
                    break;
                case EmpathyResponse.GOOD:
                    mimIdToUse = goodSleepIntentMap.get(intent);
                    break
                case EmpathyResponse.UNKNOWN:
                    mimIdToUse = unknownSleepIntentMap.get(intent);
                    break;
                default:
                    skill.log.error(`Unrecognized sleep empathy response greeting type ${previousResponse}`);
                    break;
            }

            // Save the new info and handle case where earlier saves failed
            if (data.kbRoot.data.sleepEmpathy) {
                data.kbRoot.data.sleepEmpathy[uuid] = { 
                    sleepQuality: newEmpathyResponse,
                    qualityTimestamp: now
                };
            } else {
                data.kbRoot.data.sleepEmpathy = {
                    [uuid]: {
                        sleepQuality: newEmpathyResponse,
                        qualityTimestamp: now
                    }
                };
            }

            data.kbRoot.save().catch(error => this.skill.log.error('Could not save sleep empathy interaction in kb: ', error));

            skill.log.info(`${mimIdToUse} chosen for intent:${intent} and sleep response:${previousResponse}.`);
            this.trackEmpathyResponseResult(data, previousResponse, intent);
            return mimIdToUse;
        });
    }

    /**
     * Track results of proactive greeting in a domo event.
     * @param {GreetingsRunVariables} data from this greetings run
     * @param {SimpleResponseIntent} intent of user's response
     */
    private trackEmpathyResponseResult(data: GreetingsRunVariables, previousResponse: EmpathyResponse, intent: SimpleResponseIntent) {
        const results = {
            previous_sleep_state: previousResponse, // good, bad, or unknown
            person_in_loop: ((data.user && data.user.spokenName && data.useName) ? 'true' : 'false'), // whether we knew who the user was (reused property from other events)
            user_response: intent // how the user responded (resued property from other events) all the questions boil down to "Did you sleep well last night?"
        };

        // Separate event names for the first question vs. follow-up questions
        if (previousResponse === EmpathyResponse.UNKNOWN) {
            this.skill.track('Sleep Empathy Question', results);
        } else {
            this.skill.track('Sleep Empathy Follow-up', results);
        }
    }

    public getMIMs() {
        return [SQBadAgain, SQBadNowGood, SQGoodAgain, SQGoodNowBad, SQError, SQFirstGood, SQFirstBad];
    }
}