import jibo = require('jibo');
import { GreetingsRunVariables } from '../Types';
import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../GreetingsSM';
import { YesNoState } from './primitives/YesNoState';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;


const BRIEF_GREETING = 'BriefGreeting';
/**
 * Logic for the goodMorning, goodAfternoon, goodEvening intents
 */
export class PartOfDayState extends YesNoState {

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `Part of day Intent`);
        this.onEntry = this._onEntry.bind(this);
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        const skill = this.statemachine.skill;

        skill.log.debug(`partOfDay`);
        let podClaim = data.intent.substr(4).toUpperCase();

        data.greeted = true;
        data.verbal = true;

        // if POD 'claim' matches reality
        if (skill.getPartOfDay() === podClaim) {
            data.mimId = BRIEF_GREETING;
            return this.transitionToYesState(data);
        } else {
            // TODO design calls for flashing correct POD on screen...waiting for asset
            data.PODclaim = podClaim.toLowerCase();
            data.mimId = 'PartOfDayCorrection';
            return this.transitionToNoState(data);
        }
    }
}