import { libraries } from '@be/be-framework';
import sm = libraries.jibo_state_machine;


/**
 * @internal
 */
export class DoneState extends sm.State {

    constructor(stateMachine: sm.StateMachine, name = 'Done') {
        super(stateMachine, name);
        this.onEntry = (trans, data) => {
            stateMachine.stop(data);
        };
    }
}