import { DoMIMState } from './primitives/DoMiMState';
import { GreetingsSkill } from '../GreetingsSkill';
import { libraries } from '@be/be-framework';
import { ProactiveGreetingType } from '../Types';
import sm = libraries.jibo_state_machine;


const MORNING_QUESTION = 'ProactiveMorningQuestion';
const MORNING_STATEMENT = 'ProactiveMorningStatement';
const PLAYFUL_QUESTION = 'ProactivePlayfulQuestion';
const PLAYFUL_STATEMENT = 'ProactivePlayfulStatement';
const REGULAR_QUESTION = 'ProactiveGeneralQuestion';
const REGULAR_STATEMENT = 'ProactiveGeneralStatement';


/**
 * Pick the proactive MiM to use based on probability and history 
 */
// TODO: rename this class, this name is juuuussstt terrible.
export class ProactiveProbabilityState extends DoMIMState {
    PROBABILITY_OF_STATEMENT = 0.69; // Probability that we will offer a proactive statement.

    constructor(statemachine: sm.StateMachine, skill: GreetingsSkill, name: string) {
        super(statemachine, skill, name, (sm, data) => {
            // Determine which mim to use based on probability and history

            // We want to ask questions when the user known, the question mims are more personal
            const userKnown = (data.user && data.user.uuid);
            const question = (userKnown) ? true : false;

            // Are we doing a morning, friendly, or normal proactive greeting
            if (!data.proactiveGreetingType) {
                skill.log.error('Proactive greeting type is not set in proactive greeting type state.');
                data.proactiveGreetingType = ProactiveGreetingType.REGULAR;
            }
            let greetingsType: ProactiveGreetingType = data.proactiveGreetingType;

            let mim = REGULAR_STATEMENT;
            switch (greetingsType) {
                case ProactiveGreetingType.MORNING:
                    mim = (question) ? MORNING_QUESTION : MORNING_STATEMENT; // only do a morning question if we know the user
                    break;
                case ProactiveGreetingType.PLAYFUL:
                    mim = (question) ? PLAYFUL_QUESTION : PLAYFUL_STATEMENT;
                    break;
                case ProactiveGreetingType.REGULAR:
                    mim = (question) ? REGULAR_QUESTION : REGULAR_STATEMENT;
                    break;
                default:
                    skill.log.error(`Unrecognized proactive greetings type ${greetingsType}.`);
                    break;
            }
            data.ORQuestion = question;

            if (!mim) {
                skill.log.error('No MiM chosen for proactive greetings.');
                // TODO: supply a default mim?
            }

            return mim;
        })
    }

    /**
     * Get all the mims used in this state for unit tests
     * @return a list of mims used in this state
     */
    public getMIMs() {
        return [MORNING_QUESTION,MORNING_STATEMENT,PLAYFUL_QUESTION,PLAYFUL_STATEMENT,REGULAR_QUESTION,REGULAR_STATEMENT];
    }
}