import jibo = require('jibo');
import { GreetingsSkill } from '../../GreetingsSkill';
import { GreetingsRunVariables } from '../../Types';
import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../../GreetingsSM';
const path = require('path');

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;


const GreetingsMiMFlow = require('../../flows/Greeting');

export type MIMIDSelector = (skill: GreetingsSkill, data: GreetingsRunVariables) => string[] | string | null;

/**
 * A state that handles reacting by playing a MiM (via a Flow)
 * @internal
 */
export class DoMIMState extends sm.State {

    private _flowHandle: any;

    constructor(statemachine: sm.StateMachine, public skill: GreetingsSkill, name: string, public mimIdSelector?: MIMIDSelector) {
        super(statemachine, name);
        this.onEntry = this._onEntry.bind(this);

        this.onStop = () => {
            if (this._flowHandle) {
                this._flowHandle.stop();
                this._flowHandle = null;
            }
        };
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        let mimId = data.mimId;
        let mimIds = [];
        if (this.mimIdSelector) {
            // is it a single mim or an array?
            const selectedMims = await this.mimIdSelector(this.skill, data);
            if (Array.isArray(selectedMims)) {
                mimIds.push(...selectedMims);
            } else if (selectedMims) {
                mimIds.push(selectedMims); // just one mim
            } else {
                this.skill.log.info(`mimIdSelector returned falsey value`);
                return data;
            }
        } else if (!mimId) {
            this.skill.log.error(`No mimId present`);
            return data;
        } else {
            mimIds.push(mimId); // play the mim that came in on the data object
        }

        let loopMember = '';
        if (data.user && data.user.spokenName) {
            this.skill.log.info(`loopMember: ${data.user.uuid}; useName: ${data.useName}`);
            if (data.useName) {
                loopMember = data.user.spokenName;
            }
        } else {
            this.skill.log.info('no loopMember info');
        }

        // Get day of week information for prompts
        let now = this.skill.dateProvider.getDate();
        let day = now.toLocaleDateString('en-us', { weekday: 'long' });

        const options = {
            assetPack: this.skill.assetPack,
            enableLogging: false,
            blackboard: {
                promptData: {
                    loopMember: loopMember,
                    POD: this.skill.getPartOfDay().toLowerCase(),
                    PODclaim: data.PODclaim,
                    holiday: data.holiday,
                    holidayClaim: data.holidayClaim,
                    day: day,
                    activeHolidays: data.activeHolidays
                },
                // mimPath: path.join('mims', mimId + '.mim'),
                result: {}
            },
        };

        for (let i = 0; i < mimIds.length; ++i) {
            mimId = mimIds[i];
            this.skill.log.info(`doing mim ${mimId}`);
            options.blackboard['mimPath'] = path.join('mims', mimId + '.mim');

            // go through the list of mims and play them all.
            try {
                await cu.PromiseUtils.promisify<any>(h => {
                    this._flowHandle = jibo.flow.run(GreetingsMiMFlow, options, h);
                });
            } catch (e) {
                throw e;
            } finally {
                this._flowHandle = null;
            }
        }

        // Add the results from the last mim to the data
        data.lastMiMResults = { mimId: mimId, mimResult: options.blackboard.result };

        return data;
    }

    /**
     * return the mims used in this state to check against mims folder
     * Intended to be overridden
     */
    public getMIMs() {
        return [];
    }
}
