import jibo = require('jibo');
import { GreetingsRunVariables, SpecialDayType } from '../Types';
import { BeSkill, libraries } from '@be/be-framework';
import { GreetingsSkill } from '../GreetingsSkill';
import { GreetingsSM } from '../GreetingsSM';
import { MIMIDSelector } from './primitives/DoMiMState';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

/**
 * A state that reacts to greetings about holidays.
 */
export class ReactiveHolidayState extends sm.State {

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, 'Reactive Holiday');
        this.onEntry = this._onEntry.bind(this);     
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        const skill = this.statemachine.skill;
        const holiday = BeSkill.plugins.holiday;
        
        // get a list of todays holiday names
        const todaysHolidays = await holiday.filterHolidayNamesByDate(this.statemachine.skill.dateProvider.getDate(), false);
        
        if (!todaysHolidays || todaysHolidays.length === 0 || todaysHolidays.indexOf(data.holidayClaim) === -1) {
            data.mimId = 'NotHoliday';
        } else { // it is the holiday the user claimed
            data.mimId = 'HolidayResponse';
            data.holiday = data.holidayClaim;
        }

        return data;
    }
}
