import jibo = require('jibo');
import { Utils } from '../utils/Utils';
import { GreetingsRunVariables, SpecialDayType } from '../Types';
import { BeSkill, libraries } from '@be/be-framework';
import { GreetingsSkill } from '../GreetingsSkill';
import { YesNoState } from './primitives/YesNoState';
import * as _ from 'lodash/lodash.min';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

/**
 * Evaluate whether to a birthday greeting.
 */
export class ShouldDoHolidayState extends YesNoState {
    public static MINIMUM_DAYS_BETWEEN_SPECIFIC_HOLIDAY_GREETING = 6;

    constructor(statemachine: sm.StateMachine, private skill: GreetingsSkill, name: string) {
        super(statemachine, name);

        // Make this onEntry not return anything
        this.onEntry = (trans, data) => {
            this._onEntry(trans, data);
        };
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        // get a list of todays holiday names
        const todaysHolidays = await BeSkill.plugins.holiday.filterHolidayNamesByDate(this.skill.dateProvider.getDate(), true);

        // Pick a random enabled holiday (usually only one)
        if (todaysHolidays.length > 0) {
            data.holiday = _.sample(todaysHolidays);
        } else {
            return this.transitionToNoState(data);
        }

        // check for if we've already given (this user) the special day greeting today.
        const eventQuery = {
            skillName: this.skill.assetPack
        };
        eventQuery[SpecialDayType.HOLIDAY] = true;
        if (data.user) {
            eventQuery['personIDs'] = [data.user.uuid];
        }

        // ToDo: figure out how to dodge the special day greeting we might have just done for Bday
        const dpDate = this.skill.dateProvider.getDate();
        const startDate = new Date(dpDate.getFullYear(), dpDate.getMonth(), dpDate.getDate());

        // Check if we've already given (this user) a greeting for this specific holiday
        const holidayEventQuery = _.cloneDeep(eventQuery);
        holidayEventQuery['holiday'] = data.holiday;
        const msBetweenSpecificHoliday = cu.TimeUtils.hoursToMs(24 * ShouldDoHolidayState.MINIMUM_DAYS_BETWEEN_SPECIFIC_HOLIDAY_GREETING);
        const startDateSpecificHoliday = new Date(dpDate.getTime() - msBetweenSpecificHoliday);

        let timeSinceMs = 0;
        let timeSinceSpecificHolidayMs = 0;
        try {
            // any holiday greetings in the last day?
            timeSinceMs = await jibo.im.getTimeSinceLast(eventQuery, jibo.im.compareQueryFields, startDate);
            // any specific holiday greetings in the last 6 days?
            timeSinceSpecificHolidayMs = await jibo.im.getTimeSinceLast(holidayEventQuery, jibo.im.compareQueryFields, startDateSpecificHoliday);
            this.skill.log.info(`holiday: ${data.holiday} timeSince: ${cu.TimeUtils.msToHours(timeSinceMs)} timeSinceHoliday: ${cu.TimeUtils.msToHours(timeSinceSpecificHolidayMs)}`);
        } catch (error) {
            this.skill.log.warn("Couldn't get time since last: ", error);
        }
        if (timeSinceMs < cu.TimeUtils.hoursToMs(24)) {
            // we've already done a special greeting for this holiday for this user
            this.skill.log.debug(`Already did special day greeting for this user in the last 24 hours.`);
            return this.transitionToNoState(data);
        } else if (timeSinceSpecificHolidayMs < msBetweenSpecificHoliday) {
            this.skill.log.debug(`Already did special day greeting for this user for this multi-day holiday in the last ${ShouldDoHolidayState.MINIMUM_DAYS_BETWEEN_SPECIFIC_HOLIDAY_GREETING} days.`);
            return this.transitionToNoState(data);
        }

        if (data.holiday) {
            return this.transitionToYesState(data);
        } else {
            return this.transitionToNoState(data);
        }
    }
}
