import jibo = require('jibo');
import { GreetingsRunVariables, EmpathyResponse } from '../Types';
import { Utils } from '../utils/Utils';
import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../GreetingsSM';
import { DoMIMState } from './primitives/DoMiMState';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

const SLEEP_QUALITY_GOOD = 'SleepQualityGoodAgain';
const SLEEP_QUALITY_BAD = 'SleepQualityBetter';
const SLEEP_QUALITY_UNKNOWN = 'SleepQualityUnknown';

export class SleepEmpathyQuestionState extends DoMIMState {
    constructor(private statemachine: GreetingsSM) {
        super(statemachine, statemachine.skill, `Sleep Empathy Question`, (sm, data) => {
            const skill = statemachine.skill;

            let previousSleepEmpathyResponse = EmpathyResponse.UNKNOWN;
            try {
                previousSleepEmpathyResponse = EmpathyResponse[data.kbRoot.data.sleepEmpathy[data.user.uuid].sleepQuality];
            } catch (error) {
                skill.log.error('GreetingsRunVariable is incompatible with SleepEmpathyQuestionState: ', error);
            }

            let mim = SLEEP_QUALITY_UNKNOWN;
            switch (previousSleepEmpathyResponse) {
                case EmpathyResponse.BAD:
                    mim = SLEEP_QUALITY_BAD;
                    break;
                case EmpathyResponse.GOOD:
                    mim = SLEEP_QUALITY_GOOD;
                    break;
                case EmpathyResponse.UNKNOWN:
                    mim = SLEEP_QUALITY_UNKNOWN;
                    break;
                default:
                    skill.log.error('Invalid sleep empathy response. Defaulting to UNKNOWN.');
                    break;
            }

            statemachine.skill.log.info(`Inquiring about sleep quality with mim: ${mim}`);
            return mim;
        });
    }

    public getMIMs() {
        return [SLEEP_QUALITY_BAD, SLEEP_QUALITY_GOOD, SLEEP_QUALITY_UNKNOWN];
    }
}