import jibo = require('jibo');
import { GreetingsRunVariables, SimpleResponseIntent, EmpathyResponse, BedtimeReminderIntent } from '../Types';
import { libraries } from '@be/be-framework';
import { GreetingsSkill } from '../GreetingsSkill';
import { DoMIMState } from './primitives/DoMiMState';
import { Utils } from '../utils/Utils';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

/**
 * A DoMIMState that provides a MiM response dependant on the type of sleep empathy response we get.
 */
export class BedtimeReminderResponseState extends DoMIMState {

    constructor(statemachine: sm.StateMachine, skill: GreetingsSkill) {
        super(statemachine, skill, 'Bedtime Reminder Response', (sm, data) => {
            const intentString = Utils.extractIntentFromMIMResults(data.lastMiMResults);
            this.skill.log.info(`User responded to bedtime reminder with intent ${intentString}.`);
            
            const intent = BedtimeReminderIntent[intentString] || SimpleResponseIntent.noInput; // enum of intent
            data.intentResponse = intent;

            // Record that we offered a bedtime reminder
            const user = data.user.uuid;
            const now_ms = skill.dateProvider.getDate().getTime();
            if (data.kbRoot.data.sleepEmpathy && data.kbRoot.data.sleepEmpathy[user]) {
                data.kbRoot.data.sleepEmpathy[user].reminderTimestamp = now_ms;
                data.kbRoot.save().catch(error => this.skill.log.error('Could not save bedtime reminder interaction in kb: ', error));
            } else { // should never happen
                this.skill.log.error('Bedtime reminder offered without record of users sleep.');
            }

            const mim: string = (intent !== SimpleResponseIntent.noInput) ? "BedtimeReminderResponse" : null;
            this.trackBedtimeReminderResponse(data);

            return mim;
        });
    }

    /**
     * Track results of bedtime reminder in a domo event.
     * @param {GreetingsRunVariables} data from this greetings run
     */
    private trackBedtimeReminderResponse(data: GreetingsRunVariables) {
        const results = {
            person_in_loop: ((data.user && data.user.spokenName && data.useName) ? 'true' : 'false'), // whether we knew who the user was (reused property from other events)
            user_response: data.intentResponse // how the user responded (resued property from other events)
        };

        this.skill.track('Bedtime Reminder', results);
    }

    // Return the mims used in bedtime empathy (for tests)
    getMIMs() {
        return ["BedtimeReminder", "BedtimeReminderResponse"]
    }
}