import { BeSkill, utils, libraries } from '@be/be-framework';
import jibo = require('jibo');
import { GreetingsRunVariables, SpecialDayType, EmpathyResponse } from './Types';
import { GreetingsSkill } from './GreetingsSkill';
import { DoMIMState } from './states/primitives/DoMiMState';
import { DoneState } from './states/primitives/DoneState';
import { PassThroughState } from './states/primitives/PassThroughState';
import { IntentSplit } from './states/IntentSplit';
import { PartOfDayState } from './states/PartOfDayState';
import { SelfIdState } from './states/SelfIdState';
import { ProactiveProbabilityState } from './states/ProactiveProbabilityState';
import { ProactiveOptionalResponseState } from './states/ProactiveOptionalResponseState';
import { ProactiveGreetingState } from './states/ProactiveGreetingState';
import { IsProactiveState } from './states/IsProactiveState';
import { VerbalGreetedMIMState } from './states/VerbalGreetedMiMState';
import { HeyJiboIntentState } from './states/HeyJiboIntentState';
import { SelectWhatsUpState } from './states/SelectWhatsUpState';
import { SelectHowAreYouState } from './states/SelectHowAreYouState';
import { TimeOfDayState } from './states/TimeOfDayState';
import { MaybeUseNameState } from './states/primitives/MaybeUseNameState';
import { ShouldDoBirthdayState } from './states/ShouldDoBirthdayState';
import { ShouldDoHolidayState } from './states/ShouldDoHolidayState';
import { HolidayMIMState } from './states/HolidayMiMState';
import { ReactiveHolidayState } from './states/ReactiveHolidayState';
import { ShouldDoMorningGreetingState } from './states/ShouldDoMorningGreetingState';
import { ChooseMorningGreetingState } from './states/ChooseMorningGreetingState';
import { HelloState } from './states/HelloState';
import { ShouldDoSleepEmpathy } from './states/ShouldDoSleepEmpathy';
import { SleepEmpathyQuestionState } from './states/SleepEmpathyQuestionState';
import { SleepEmpathyResponseState } from './states/SleepEmpathyResponseState';
import { ShouldDoBedtimeReminderState } from './states/ShouldDoBedtimeReminderState';
import { BedtimeReminderState } from './states/BedtimeReminderState';
import { BedtimeReminderResponseState } from './states/BedtimeReminderResponseState';
import { ShouldDoDayEmpathyState } from './states/ShouldDoDayEmpathyState';
import { DayEmpathyQuestionState } from './states/DayEmpathyQuestionState';
import { DayEmpathyResponseState } from './states/DayEmpathyResponseState';

import sm = libraries.jibo_state_machine;


export class GreetingsSM extends sm.StateMachine {

    intentSplitState = new IntentSplit(this);
    doneState = new DoneState(this);

    // MIM states
    variableMIMNoListenState = new DoMIMState(this, this.skill, 'Variable MIM (no listen)');

    goodbyeState = new VerbalGreetedMIMState(this, this.skill, 'Goodbye MIM', () => 'GoodbyeRespCM');
    goodnightState = new VerbalGreetedMIMState(this, this.skill, 'Good night MIM', () => 'GoodnightResponse');
    imHomeState = new VerbalGreetedMIMState(this, this.skill, `I'm home MIM`, () => 'IAmHome');
    imBackState = new VerbalGreetedMIMState(this, this.skill, `I'm back MIM`, () => 'IAmBack');

    heyJiboState = new HeyJiboIntentState(this);
    proactiveGreetingState = new ProactiveGreetingState(this);
    selfIDState = new SelfIdState(this);
    partOfDayState = new PartOfDayState(this);

    // Hello intent states
    helloState = new HelloState(this);

    // Whatsup intent states
    whatsUpState = new SelectWhatsUpState(this);

    // Special Day states
    shouldDoBirthdayState = new ShouldDoBirthdayState(this, this.skill, `Should Do Birthday?`);
    shouldDoHolidayState1 = new ShouldDoHolidayState(this, this.skill, `Should Do Holiday? (no Bday)`);
    shouldDoHolidayState2 = new ShouldDoHolidayState(this, this.skill, `Should Do Holiday? (with Bday)`);
    birthdayMiMState = new HolidayMIMState(this, this.skill, 'Happy Birthday MiM', SpecialDayType.BIRTHDAY, () => 'HappyBirthdayToYou');
    holidayMiMState = new HolidayMIMState(this, this.skill, 'Holiday MiM', SpecialDayType.HOLIDAY, () => 'Holiday');
    alsoHolidayMimState = new DoMIMState(this, this.skill, 'Also Holiday', () => 'AlsoHoliday');

    // Reactive Holiday state (for reacting to holiday greetings)
    reactiveHolidayState = new ReactiveHolidayState(this);

    // Morning Greeting states
    shouldDoMorningGreetingState = new ShouldDoMorningGreetingState(this);
    chooseMorningGreetingState = new ChooseMorningGreetingState(this);

    // Proactive optional response states
    isProactiveState: IsProactiveState;
    proactiveVariableMIMState: ProactiveProbabilityState;
    proactiveOptionalResponseState: ProactiveOptionalResponseState;

    // Sleep Empathy States
    shouldDoSleepEmpathyState: ShouldDoSleepEmpathy;
    sleepEmpathyQuestionState: SleepEmpathyQuestionState;
    sleepEmpathyResponseState: SleepEmpathyResponseState;
    shouldDoBedtimeReminderState: ShouldDoBedtimeReminderState;
    bedtimeReminderState: BedtimeReminderState;
    bedtimeReminderResponseState: BedtimeReminderResponseState;

    // Day Empathy States
    shouldDoDayEmpathyState: ShouldDoDayEmpathyState;
    dayEmpathyQuestionState: DayEmpathyQuestionState;
    dayEmpathyResponseState: DayEmpathyResponseState;

    constructor(public skill: GreetingsSkill) {
        super();

        this.setInitial(this.intentSplitState);
        this.intentSplitState.init();

        // Connect all the simple intents
        this.heyJiboState.addDoneTransition(this.variableMIMNoListenState);
        this.selfIDState.addDoneTransition(this.variableMIMNoListenState);
        this.reactiveHolidayState.addDoneTransition(this.variableMIMNoListenState);

        // These all result in their own MIM playing, so they go straight to done
        this.goodbyeState.addDoneTransition(this.doneState);
        this.goodnightState.addDoneTransition(this.doneState);
        this.imHomeState.addDoneTransition(this.doneState);
        this.imBackState.addDoneTransition(this.doneState);

        // Connect the 'hello' intent
        this.helloState.addDoneTransition(this.shouldDoBirthdayState);

        // Connect the 'whatsup' intent
        this.whatsUpState.addDoneTransition(this.shouldDoBirthdayState);

        // Connect the 'proactiveGreeting' intent
        this.proactiveGreetingState.init(this.shouldDoBirthdayState, this.variableMIMNoListenState, ['Verbal', 'Nonverbal']);

        // Part of Day intents
        this.partOfDayState.init(this.shouldDoBirthdayState, this.variableMIMNoListenState, ['Normal', 'WrongToD']);

        // Wire up the Special day stuff
        this.shouldDoBirthdayState.init(this.birthdayMiMState, this.shouldDoHolidayState1);
        this.birthdayMiMState.addDoneTransition(this.shouldDoHolidayState2);
        this.shouldDoHolidayState1.init(this.holidayMiMState, this.shouldDoMorningGreetingState);
        this.shouldDoHolidayState2.init(this.alsoHolidayMimState, this.doneState);
        this.alsoHolidayMimState.addDoneTransition(this.holidayMiMState);

        // TODO: Make fork to allow Sleep empathy questions to be turned on or off
        // switch for allowing/prohibiting optional responses
        if (this.skill.ALLOW_OPTIONAL_RESPONSE) {
            this.skill.log.info("Setup allowing optional responses.");
            this.initWithOptionalResponses();
        } else {
            this.skill.log.info("Setup prohibiting optional responses.");
            this.initWithoutOptionalResponses();
        }
    }

    /**
     * init states with optional response logic
     */
    initWithOptionalResponses() {
        // initialize OR states
        this.isProactiveState = new IsProactiveState(this);
        this.proactiveVariableMIMState = new ProactiveProbabilityState(this, this.skill, 'Variable Random Proactive MiM'); // where initial mim selection happens 
        this.proactiveOptionalResponseState = new ProactiveOptionalResponseState(this, this.skill, 'Optional Response MiM'); // respond to optional response based on history and user intent

        if (this.skill.ALLOW_SLEEP_EMPATHY) {         
            // initialize sleep empathy states
            this.shouldDoSleepEmpathyState = new ShouldDoSleepEmpathy(this);
            this.sleepEmpathyQuestionState = new SleepEmpathyQuestionState(this);
            this.sleepEmpathyResponseState = new SleepEmpathyResponseState(this, this.skill);
            this.shouldDoBedtimeReminderState = new ShouldDoBedtimeReminderState(this);
            this.bedtimeReminderState = new BedtimeReminderState(this, this.skill);
            this.bedtimeReminderResponseState = new BedtimeReminderResponseState(this, this.skill);

            // initialize day empathy states
            this.shouldDoDayEmpathyState = new ShouldDoDayEmpathyState(this);
            this.dayEmpathyQuestionState = new DayEmpathyQuestionState(this);
            this.dayEmpathyResponseState = new DayEmpathyResponseState(this, this.skill);

            // Morning greeting stuff
            this.shouldDoMorningGreetingState.init(this.chooseMorningGreetingState, this.shouldDoBedtimeReminderState);
            this.chooseMorningGreetingState.addDoneTransition(this.shouldDoSleepEmpathyState);

            // empathy branches
            this.shouldDoBedtimeReminderState.init(this.bedtimeReminderState, this.shouldDoDayEmpathyState);
            this.shouldDoDayEmpathyState.init(this.dayEmpathyQuestionState, this.isProactiveState);
            this.shouldDoSleepEmpathyState.init(this.sleepEmpathyQuestionState, this.isProactiveState);

            // empathy paths
            this.sleepEmpathyQuestionState.addDoneTransition(this.sleepEmpathyResponseState);
            this.sleepEmpathyResponseState.addDoneTransition(this.doneState);
            this.bedtimeReminderState.addDoneTransition(this.bedtimeReminderResponseState);
            this.bedtimeReminderResponseState.addDoneTransition(this.doneState);
            this.dayEmpathyQuestionState.addDoneTransition(this.dayEmpathyResponseState);
            this.dayEmpathyResponseState.addDoneTransition(this.doneState);
        } else {
            this.shouldDoMorningGreetingState.init(this.chooseMorningGreetingState, this.isProactiveState);
            this.chooseMorningGreetingState.addDoneTransition(this.isProactiveState);
        }

        // Proactive branch
        this.isProactiveState.init(this.proactiveVariableMIMState, this.variableMIMNoListenState);

        // The proactive variable mim state will decide whether to play a ProactiveGeneralStatement or a ProactiveGeneralQuestion.
        this.proactiveVariableMIMState.addDoneTransition(this.proactiveOptionalResponseState);
        this.proactiveOptionalResponseState.addDoneTransition(this.doneState);

        // These are all the final states that go straight to done
        this.holidayMiMState.addDoneTransition(this.doneState);
        this.variableMIMNoListenState.addDoneTransition(this.doneState);
    }

    /**
     * init states without optional response logic
     */
    initWithoutOptionalResponses() {
        if (this.skill.ALLOW_SLEEP_EMPATHY) {
            // initialize sleep empathy states
            this.shouldDoSleepEmpathyState = new ShouldDoSleepEmpathy(this);
            this.sleepEmpathyQuestionState = new SleepEmpathyQuestionState(this);
            this.sleepEmpathyResponseState = new SleepEmpathyResponseState(this, this.skill);
            this.shouldDoBedtimeReminderState = new ShouldDoBedtimeReminderState(this);
            this.bedtimeReminderState = new BedtimeReminderState(this, this.skill);
            this.bedtimeReminderResponseState = new BedtimeReminderResponseState(this, this.skill);

            // initialize day empathy states
            this.shouldDoDayEmpathyState = new ShouldDoDayEmpathyState(this);
            this.dayEmpathyQuestionState = new DayEmpathyQuestionState(this);
            this.dayEmpathyResponseState = new DayEmpathyResponseState(this, this.skill);

            // Morning greeting stuff
            this.shouldDoMorningGreetingState.init(this.chooseMorningGreetingState, this.shouldDoBedtimeReminderState);
            this.chooseMorningGreetingState.addDoneTransition(this.shouldDoSleepEmpathyState);
            this.shouldDoSleepEmpathyState.init(this.sleepEmpathyQuestionState, this.variableMIMNoListenState);
            this.shouldDoBedtimeReminderState.init(this.bedtimeReminderState, this.variableMIMNoListenState);
            this.shouldDoDayEmpathyState.init(this.dayEmpathyQuestionState, this.variableMIMNoListenState);

            this.sleepEmpathyQuestionState.addDoneTransition(this.sleepEmpathyResponseState);
            this.sleepEmpathyResponseState.addDoneTransition(this.doneState);
            this.bedtimeReminderState.addDoneTransition(this.bedtimeReminderResponseState);
            this.bedtimeReminderResponseState.addDoneTransition(this.doneState);
            this.dayEmpathyQuestionState.addDoneTransition(this.dayEmpathyResponseState);
            this.dayEmpathyResponseState.addDoneTransition(this.doneState);
        } else {
            // Morning Greeting stuff
            this.shouldDoMorningGreetingState.init(this.chooseMorningGreetingState, this.variableMIMNoListenState);
            this.chooseMorningGreetingState.addDoneTransition(this.variableMIMNoListenState);
        }
        
        // These are all the final states that go straight to done
        this.holidayMiMState.addDoneTransition(this.doneState);
        this.variableMIMNoListenState.addDoneTransition(this.doneState);
    }
}
