import { BeSkill, utils, libraries } from '@be/be-framework';
import { GreetingsSkill } from '../GreetingsSkill';
import jibo = require('jibo');

const { PromiseUtils } = libraries.jibo_cai_utils;

export class LoopUtils {

    constructor(private skill: GreetingsSkill) {
    }

    /**
     * Gets the spoken name from the KB
     * @param uuid
     * @returns {any}
     */
    async spokenNameFromUUID(uuid: string): Promise<string> {
        this.skill.log.debug(`accessing loopManager...`);
        let loop = undefined; // TODO: could use some typing here...
        try {
            loop = await this.fetchLoopMemberList();
        } catch (e) {
            this.skill.log.error(`error populating loop info: `, e);
            return null;
        }
        this.skill.log.debug(`got loop info`);
        let loopMemberNode: jibo.kb.UserNode = loop.find((element) => element.id === uuid);
        if (!loopMemberNode) {
            this.skill.log.warn(`${uuid} not found in loop`);
            return null;
        } else {
            // turns out the UserNode object is designed with a toString method that does the right thing
            // (returns userNode.data.phoneticName || userNode.data.nickName || userNode.data.firstName)
            let name = loopMemberNode.toString();
            this.skill.log.info(`loopMemberNode found for: ${uuid}`); // can't log the name.
            return name;
        }
    }

    /**
     *
     * @param loopMemberUUID
     * @returns {Promise<boolean>} a promise of a boolean: true if today is the loopMember's birthday
     * @private
     */
    async isLoopMemberBday(loopMemberUUID: string): Promise<boolean> {
        const loopMemberList = await this.fetchLoopMemberList();
        if (!loopMemberList || !loopMemberList.length) {
            this.skill.log.warn('no loop member list when checking loop member birthday');
            return false;
        }

        // iterate through the members to find the one that matches
        for (const member of loopMemberList) {
            if (member.id === loopMemberUUID && member.data.birthday) {
                // we found the match! (and the birthday property exists)
                const bdayValue = member.data.birthday;

                // bdayValue is milliseconds since the epoch
                const bday = new Date(bdayValue);
                const dpDate = this.skill.dateProvider.getDate();

                // Birthday should not have a timezone associated,
                // e.g., if you are borned in Taiwan on 7/28 and move
                // to the U.S., as long as it is 7/28 in the U.S.,
                // it is your birthday.
                if (bday.getUTCDate() === dpDate.getDate() &&
                    bday.getUTCMonth() === dpDate.getMonth()) {
                    // month and day match
                    return true;
                }
            }
        }
        return false;
    }

    /**
     * Fetches the loop list
     * @return {Promise<jibo.kb.UserNode[]|null>}
     */
    public async fetchLoopMemberList(): Promise<jibo.kb.UserNode[]> {
        let loopMemberList;
        try {
            loopMemberList = await jibo.kb.loop.loadLoop();
        } catch (err) {
            this.skill.log.error(`Error loading loop from KB. Returning null.`);
            return null;
        }

        if (!loopMemberList) {
            this.skill.log.warn(`KB returned no loop.`);
            return null;
        }
        return loopMemberList;
    }
}
