export class DateProvider {
    offset: number;

    constructor(offset = 0) {
        this.offset = offset;
    }

    /**
     * @return A Date object representing the current time given
     *         the timezone of the robot
     */
    getDate(): Date {
        // This is to compensate for the fact that the system time on robot is always in UTC
        const dateInOSLocal = new Date();
        var dateUTC = new Date(
            dateInOSLocal.getUTCFullYear(),
            dateInOSLocal.getUTCMonth(),
            dateInOSLocal.getUTCDate(),
            dateInOSLocal.getUTCHours(),
            dateInOSLocal.getUTCMinutes(),
            dateInOSLocal.getUTCSeconds());

        return new Date(dateUTC.getTime() + this.offset);
    }
}

