import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../GreetingsSM';
import { GreetingsRunVariables, Intents, ProactiveGreetingType } from '../Types';

import sm = libraries.jibo_state_machine;

export class ChooseMorningGreetingState extends sm.State {
    
    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `Choose Morning Greeting`);
        this.onEntry = this._onEntry.bind(this);
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        // TODO: add logic for early morning! ...only once we've got learned temporal pattern info
        switch (data.intent) {
            case Intents.proactiveGreeting:
                data.mimId = 'GoodMorningProactive';
                break;
            case Intents.goodMorning:
                // do response to morning greeting
                data.mimId = 'GoodMorningEcho';
                break;
            case Intents.hello: // intentional fall-throughs!
            case Intents.whatsUp: // we expect these two cases, but don't actually need to do anything different than default
            default: // ...and we want the default case just in case something wacky happens
                // just do a regular morning greeting
                data.mimId = 'GoodMorningReactive';
        }

        // I'd actually rather set these at the mim delivery point, but that's a pedantic refactor for later.
        data.greeted = true;
        data.verbal = true;
        data.proactiveGreetingType = ProactiveGreetingType.MORNING;

        return data;
    }
}