import jibo = require('jibo');
import { GreetingsRunVariables, EmpathyResponse } from '../Types';
import { Utils } from '../utils/Utils';
import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../GreetingsSM';
import { DoMIMState } from './primitives/DoMiMState';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

const DAY_QUALITY_GOOD = 'DayQualityGoodAgain';
const DAY_QUALITY_BAD = 'DayQualityBetter';
const DAY_QUALITY_UNKNOWN = 'DayQualityUnknown';

export class DayEmpathyQuestionState extends DoMIMState {
    constructor(private statemachine: GreetingsSM) {
        super(statemachine, statemachine.skill, `Day Empathy Question`, (sm, data) => {
            const skill = statemachine.skill;

            let previousDayEmpathyResponse = EmpathyResponse.UNKNOWN;
            try { // in case something failed during initialziation
                previousDayEmpathyResponse = EmpathyResponse[data.kbRoot.data.dayEmpathy[data.user.uuid].dayQuality];
            } catch (error) {
                skill.log.error('GreetingsRunVariable is incompatible with DayEmpathyQuestionState: ', error);
            }

            let mim = DAY_QUALITY_UNKNOWN;
            switch (previousDayEmpathyResponse) {
                case EmpathyResponse.BAD:
                    mim = DAY_QUALITY_BAD;
                    break;
                case EmpathyResponse.GOOD:
                    mim = DAY_QUALITY_GOOD;
                    break;
                case EmpathyResponse.UNKNOWN:
                    mim = DAY_QUALITY_UNKNOWN;
                    break;
                default:
                    skill.log.error('Invalid day empathy response. Defaulting to UNKNOWN.');
                    break;
            }

            skill.log.info(`Inquiring about day quality with mim: ${mim}`);
            return mim;
        });
    }

    public getMIMs() {
        return [DAY_QUALITY_BAD, DAY_QUALITY_GOOD, DAY_QUALITY_UNKNOWN];
    }
}