import { libraries } from '@be/be-framework';
import { GreetingsSM } from '../GreetingsSM';
import { GreetingsRunVariables } from '../Types';

import sm = libraries.jibo_state_machine;
import cu = libraries.jibo_cai_utils;

const BRIEF_GREETING = 'BriefGreeting';

export class HelloState extends sm.State {

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `Hello`);
        this.onEntry = this._onEntry.bind(this);
    }

    async _onEntry(trans, data: GreetingsRunVariables): Promise<any> {
        data.mimId = BRIEF_GREETING;
        // TODO: refactor so greeted and verbal are set at mim delivery time?
        data.greeted = true;
        data.verbal = true;
        return data;
    }
}
