import { libraries } from '@be/be-framework';
const { PromiseUtils, RandomUtils } = libraries.jibo_cai_utils;
import { GreetingsRunVariables } from '../../Types';

import sm = libraries.jibo_state_machine;


/**
 * @internal
 */
export class YesNoState extends sm.State {

    private yesState: sm.State;
    private noState: sm.State;

    constructor(statemachine: sm.StateMachine, name = 'Yes/No') {
        super(statemachine, name);
    }

    init(yesState: sm.State, noState: sm.State, transitionNames = ['yes', 'no']) {
        this.yesState = yesState;
        this.noState = noState;
        this.addInternalTransition(transitionNames[0], this.yesState);
        this.addInternalTransition(transitionNames[1], this.noState);
    }

    transitionToYesState(data: GreetingsRunVariables) {
        if (this.isCurrent()) {
            return this.transitionTo(this.yesState, data);
        }
    }

    transitionToNoState(data: GreetingsRunVariables) {
        if (this.isCurrent()) {
            return this.transitionTo(this.noState, data);
        }
    }
}