import jibo = require('jibo');
import { libraries } from '@be/be-framework';
import sm = libraries.jibo_state_machine;
import { GreetingsRunVariables, Intents } from '../Types';
import { GreetingsSM } from '../GreetingsSM';
import { YesNoState } from './primitives/YesNoState';

export class ShouldDoMorningGreetingState extends YesNoState {

    constructor(private statemachine: GreetingsSM) {
        super(statemachine, `Should Do Morning Greeting?`);
        this.onEntry = this._onEntry.bind(this);
    }

    async _onEntry(trans, data: GreetingsRunVariables) {
        const skill = this.statemachine.skill;

        // is it the morning?
        let pod = skill.getPartOfDay();
        if (pod !== 'MORNING') {
            // take the no path
            return this.transitionToNoState(data);
        }
        // did the user say good morning to me?
        if (data.intent === Intents.goodMorning) {
            // take the yes path
            return this.transitionToYesState(data);
        }
        // is this the first time we've interacted with this person today?
        let evtDesc;
        // if we have an IDed user, we check first time interacted with that user today
        // if we don't, we check whether first time verbally greeting today.
        if (data.user) {
            evtDesc = {
                personIDs: [data.user.uuid],
            };
        } else {
            evtDesc = {
                skillName: skill.assetPack,
                verbal: true
            };
        }

        const today = skill.dateProvider.getDate();
        // 5am today. I wish this weren't so hardcoded, but we don't actually define these boundaries in a portable way. To fix someday...
        const morningStart = new Date(today.getFullYear(), today.getMonth(), today.getDate(), 5);
        let timeSince = 0;
        try {
            timeSince = await jibo.im.getTimeSinceLast(evtDesc, jibo.im.compareQueryFields, morningStart);
        } catch (error) {
            this.statemachine.skill.log.warn("Couldn't get time since last: ", error);
        }
        if (timeSince < Number.POSITIVE_INFINITY) {
            // we've already had an interaction with this person today - no morning greeting
            return this.transitionToNoState(data);
        } else {
            // we are go for morning greeting
            return this.transitionToYesState(data);
        }
    }
}
